   123	
   124	    switch (var->type->spec) {
   125	      case Type::Spec::kChar:
   126	      case Type::Spec::kInt:
   127	      case Type::Spec::kLong:
   128	      case Type::Spec::kLongLong:
   129	        return eval_arrlen(var->init);
   130	
   131	      default:
   132	        ABORT(); // 长度表达式必须是数值类型
   133	    }
   134	  }
   135	
   136	  if (auto p = expr->dcst<UnaryExpr>()) {
   137	    auto sub = eval_arrlen(p->sub);
   138	
   139	    switch (p->op) {
   140	      case UnaryExpr::kPos:
   141	        return sub;
   142	
   143	      case UnaryExpr::kNeg:
   144	        return -sub;
   145	
   146	      default:
   147	        ABORT();
   148	    }
   149	  }
   150	
   151	  if (auto p = expr->dcst<BinaryExpr>()) {
   152	    auto lft = eval_arrlen(p->lft);
   153	    auto rht = eval_arrlen(p->rht);
   154	
   155	    switch (p->op) {
   156	      case BinaryExpr::kAdd:
